    "# =========================\n",
    "# MODEL / STRATEGY PARAMETERS\n",
    "# =========================\n",
    "\n",
    "PCA_LOOKBACK = 252\n",
    "N_PCA_FACTORS = 3\n",
    "OU_WINDOW = 60\n",
    "\n",
    "ENTRY_THRESHOLD = 1.75\n",
