    "TRANSACTION_COST_BPS = 5\n",
    "TRANSACTION_COST = TRANSACTION_COST_BPS / 10000\n",
    "\n",
    "# target gross leverage after stock + factor hedge weights are built\n",
    "TARGET_GROSS = 2.0\n",
    "\n",
    "# =========================\n",
    "# KALMAN PARAMETERS\n",
    "# =========================\n",
    "\n",
    "# discount factors (controls how fast model adapts)\n",
