    "\n",
    "# initial state\n",
    "KF_INIT_A = 0.0\n",
    "KF_INIT_B = 0.9\n",
    "\n",
    "# initial uncertainty\n",
    "KF_INIT_VAR = 0.01\n",
    "\n",
    "# variance priors\n",
    "KF_INIT_N = 1e-5\n",
    "KF_INIT_D = 1e-6\n",
    "\n",
